-- Publish the collected venue dashboard as a public planning layer.
-- Source files: OZO_BaliWali_venue_dashboard.html + OZO_BaliWali_all_venues_dashboard.csv (2026-07-11 exports).
-- Imported rows: 221 real collected venues: 151 previously prepared rows plus
-- 70 additional rows from the all-venues CSV. The 9 local seed placeholders
-- are intentionally excluded because they are not verified places.
--
-- Guardrails:
-- - This imports venues only: no perks, no QR posters, no plan_entries, no
--   TablePilot slugs, and no paid ranking.
-- - Non-Canggu districts remain planning_only with monetization_enabled=false
--   and qr_enabled=false; record_redemption() already rejects QR outside a
--   qr-enabled district.
-- - Raw complaints/red flags/confidence/internal QA fields are intentionally not
--   published to tourists. They stay in the research dashboard and field-QA
--   prompt.
-- - Non-English source notes and CSV QA notes are not imported into public copy;
--   those rows stay visible with factual name/area/category only until rewritten
--   in English.

insert into districts (slug, name, is_deep, status, monetization_enabled, qr_enabled) values
  ('canggu',        'Canggu',                    true,  'active_deep',   true,  true),
  ('ubud',          'Ubud',                      false, 'next_deep',     false, false),
  ('seminyak',      'Seminyak',                  false, 'planning_only', false, false),
  ('kuta-legian',   'Kuta & Legian',             false, 'planning_only', false, false),
  ('jimbaran',      'Jimbaran',                  false, 'planning_only', false, false),
  ('uluwatu-bukit', 'Uluwatu & the Bukit',       false, 'planning_only', false, false),
  ('nusa-dua',      'Nusa Dua',                  false, 'planning_only', false, false),
  ('sanur',         'Sanur',                     false, 'planning_only', false, false),
  ('sidemen',       'Sidemen',                   false, 'planning_only', false, false),
  ('amed',          'Amed & the east coast',     false, 'planning_only', false, false),
  ('munduk',        'Munduk & the highlands',    false, 'planning_only', false, false),
  ('lovina',        'Lovina',                    false, 'planning_only', false, false),
  ('nusa-islands',  'Nusa Penida & the islands', false, 'planning_only', false, false),
  ('gili-islands',  'Gili Islands',              false, 'planning_only', false, false),
  ('lombok',        'Lombok',                    false, 'planning_only', false, false)
on conflict (slug) do update set
  name = excluded.name,
  status = excluded.status,
  monetization_enabled = excluded.monetization_enabled,
  qr_enabled = excluded.qr_enabled;

